using BgControls.Windows.Controls.PropertyGrid;using BgControls.Windows.Controls.PropertyGrid.Attributes;namespace BgControls.Windows.Controls.PropertyGrid;/// <summary>/// PropertyGrid 动态逻辑控制帮助类 (支持 VisibleBy 和 EnableBy)./// </summary>public static class PropertyLogicHelper{    #region 公开方法 (API)    /// <summary>    /// 全量扫描所有属性，主动触发一次“推模式”的更新 (包含可见性和启用状态).    /// </summary>    /// <param name="rootProperties">PropertyGrid 的根属性集合 (this.Properties).</param>    public static void Initialize(this IEnumerable<PropertyItem> rootProperties)    {        if (rootProperties == null)        {            return;        }        var rootList = rootProperties.ToList();        // 递归遍历整棵树，找到所有作为“控制源”的属性，执行一次更新        RecursivelyApplyRules(rootList, rootList);    }    /// <summary>    /// 当属性值变化时，根据规则查找目标作用域并更新.    /// </summary>    /// <param name="sourceItem">发生值变化的源属性项.</param>    /// <param name="rootProperties">PropertyGrid 的根属性集合 (用于路径导航).</param>    public static void OnHandlePropertyValueChanged(this PropertyItem sourceItem, IEnumerable<PropertyItem> rootProperties)    {        if (rootProperties == null || sourceItem == null)        {            return;        }        var rootList = rootProperties.ToList();        // 1. 处理可见性规则 (VisibleBy)        HandleVisibleRules(sourceItem, rootList);        // 2. 处理启用状态规则 (EnableBy)        HandleEnableRules(sourceItem, rootList);    }    #endregion    #region 递归与入口逻辑    /// <summary>    /// 递归遍历树，对每一个有规则的属性执行规则应用.    /// </summary>    private static void RecursivelyApplyRules(List<PropertyItem> currentScope, List<PropertyItem> rootList)    {        foreach (var item in currentScope)        {            if (item.HasExtendedAttributes)            {                item.OnHandlePropertyValueChanged(rootList);            }            // 递归子项            if (item.Properties != null && item.Properties.Count > 0)            {                RecursivelyApplyRules(item.Properties.Cast<PropertyItem>().ToList(), rootList);            }        }    }    #endregion    #region 逻辑分支 1: VisibleBy 处理    /// <summary>    /// 处理可见性规则的分组与应用.    /// </summary>    private static void HandleVisibleRules(PropertyItem sourceItem, List<PropertyItem> rootList)    {        if (sourceItem.VisibleToAttributes == null || sourceItem.VisibleToAttributes.Count == 0)        {            return;        }        // 按作用域路径分组        var grouped = sourceItem.VisibleToAttributes            .Select(attr => new { Attribute = attr, Parsed = ParseAttributeTarget(attr.Name) })            .GroupBy(x => x.Parsed.ScopePath);        foreach (var group in grouped)        {            // 解析作用域            List<PropertyItem>? targetScope = sourceItem.FindScopeByPath(group.Key, rootList);            if (targetScope == null)            {                continue;            }            // 应用规则            ApplyVisibilityRulesToScope(                targetScope,                sourceItem.Value,                group.Select(g => new RuleContext<VisibleToAttribute>(g.Parsed.TargetName, g.Attribute)));        }    }    /// <summary>    /// 在指定作用域内批量应用可见性规则.    /// </summary>    private static void ApplyVisibilityRulesToScope(List<PropertyItem> scopeList, object sourceValue, IEnumerable<RuleContext<VisibleToAttribute>> rules)    {        if (scopeList.Count == 0 || rules == null || !rules.Any())        {            return;        }        var categoryRules = new Dictionary<string, bool>();        var propertyRules = new Dictionary<string, bool>();        // 1. 预计算规则结果        foreach (var ctx in rules)        {            bool isVisible = IsConditionMet(sourceValue, ctx.Attribute.When);            if (ctx.Attribute.Target == PropertyGridTarget.Categorized)            {                categoryRules[ctx.TargetName] = isVisible;            }            else if (ctx.Attribute.Target == PropertyGridTarget.Property)            {                propertyRules[ctx.TargetName] = isVisible;            }        }        // 2. 应用到属性        foreach (var item in scopeList)        {            bool? finalState = null;            // 优先级 1: 分类规则            if (item.Category != null && categoryRules.TryGetValue(item.Category, out bool catVis))            {                finalState = catVis;            }            // 优先级 2: 属性规则 (覆盖分类)            if (propertyRules.TryGetValue(item.PropertyDescriptor.Name, out bool propVis))            {                finalState = propVis;            }            // 3. 执行变更            if (finalState.HasValue)            {                var newVisibility = finalState.Value ? Visibility.Visible : Visibility.Collapsed;                if (item.Visibility != newVisibility)                {                    item.Visibility = newVisibility;                }            }        }    }    #endregion    #region 逻辑分支 2: EnableBy 处理    /// <summary>    /// 处理启用状态规则的分组与应用.    /// </summary>    private static void HandleEnableRules(PropertyItem sourceItem, List<PropertyItem> rootList)    {        if (sourceItem.EnableToAttributes == null || sourceItem.EnableToAttributes.Count == 0)        {            return;        }        // 按作用域路径分组        var grouped = sourceItem.EnableToAttributes            .Select(attr => new { Attribute = attr, Parsed = ParseAttributeTarget(attr.Name) })            .GroupBy(x => x.Parsed.ScopePath);        foreach (var group in grouped)        {            List<PropertyItem>? targetScope = sourceItem.FindScopeByPath(group.Key, rootList);            if (targetScope == null)            {                continue;            }            // 应用规则            ApplyEnableRulesToScope(                targetScope,                sourceItem.Value,                group.Select(g => new RuleContext<EnableToAttribute>(g.Parsed.TargetName, g.Attribute)));        }    }    /// <summary>    /// 在指定作用域内批量应用启用状态规则.    /// </summary>    private static void ApplyEnableRulesToScope(List<PropertyItem> scopeList, object sourceValue, IEnumerable<RuleContext<EnableToAttribute>> rules)    {        if (scopeList.Count == 0 || rules == null || !rules.Any())        {            return;        }        var categoryRules = new Dictionary<string, bool>();        var propertyRules = new Dictionary<string, bool>();        // 1. 预计算规则结果        foreach (var ctx in rules)        {            bool isEnabled = IsConditionMet(sourceValue, ctx.Attribute.When);            if (ctx.Attribute.Target == PropertyGridTarget.Categorized)            {                categoryRules[ctx.TargetName] = isEnabled;            }            else if (ctx.Attribute.Target == PropertyGridTarget.Property)            {                propertyRules[ctx.TargetName] = isEnabled;            }        }        // 2. 应用到属性        foreach (var item in scopeList)        {            bool? finalState = null;            // 优先级 1: 分类规则            if (item.Category != null && categoryRules.TryGetValue(item.Category, out bool catEnabled))            {                finalState = catEnabled;            }            // 优先级 2: 属性规则 (覆盖分类)            if (propertyRules.TryGetValue(item.PropertyDescriptor.Name, out bool propEnabled))            {                finalState = propEnabled;            }            // 3. 执行变更 (设置 IsEnabled)            if (finalState.HasValue)            {                if (item.IsEnabled != finalState.Value)                {                    item.IsEnabled = finalState.Value;                }            }        }    }    #endregion    #region 上下文与辅助结构    /// <summary>    /// 泛型规则上下文，用于传递目标名称和特性实例.    /// </summary>    /// <typeparam name="TAttribute">特性类型 (VisibleByAttribute 或 EnableByAttribute).</typeparam>    private class RuleContext<TAttribute>        where TAttribute : Attribute    {        public RuleContext(string targetName, TAttribute attr)        {            this.TargetName = targetName;            this.Attribute = attr;        }        /// <summary>        /// Gets 规则指向的目标名称.        /// </summary>        public string TargetName { get; }        /// <summary>        /// Gets 对应的特性实例.        /// </summary>        public TAttribute Attribute { get; }    }    #endregion    #region 通用辅助逻辑    /// <summary>    /// 解析 Attribute.Name 字符串, 分离目标名称和路径.    /// </summary>    /// <returns>返回包含目标名称和路径的元组.</returns>    private static (string TargetName, string ScopePath) ParseAttributeTarget(string rawName)    {        if (string.IsNullOrEmpty(rawName))        {            return (string.Empty, string.Empty);        }        int pipeIndex = rawName.IndexOf('|');        if (pipeIndex < 0)        {            return (rawName.Trim(), string.Empty);        }        string name = rawName.Substring(0, pipeIndex).Trim();        string path = rawName.Substring(pipeIndex + 1).Trim();        return (name, string.IsNullOrEmpty(path) ? string.Empty : path);    }    /// <summary>    /// 根据路径查找作用域.    /// </summary>    private static List<PropertyItem>? FindScopeByPath(this PropertyItem sourceItem, string path, List<PropertyItem> rootList)    {        if (string.IsNullOrEmpty(path))        {            return sourceItem.FindSiblingScope(rootList)?.ToList();        }        List<PropertyItem> currentLevel = rootList;        var parts = path.Split('.');        foreach (var part in parts)        {            var container = currentLevel.FirstOrDefault(p => p.PropertyDescriptor.Name == part);            if (container == null || container.Properties == null || container.Properties.Count == 0)            {                return null;            }            currentLevel = container.Properties.Cast<PropertyItem>().ToList();        }        return currentLevel;    }    /// <summary>    /// 查找同级作用域 (递归查找包含指定 Target 的集合).    /// </summary>    private static List<PropertyItem>? FindSiblingScope(this PropertyItem target, IEnumerable<PropertyItem> rootProperties)    {        var currentLevel = rootProperties.ToList();        if (currentLevel.Contains(target))        {            return currentLevel;        }        foreach (var item in currentLevel)        {            if (item.Properties != null && item.Properties.Count > 0)            {                var found = target.FindSiblingScope(item.Properties.Cast<PropertyItem>());                if (found != null)                {                    return found;                }            }        }        return null;    }    /// <summary>    /// 判断当前值是否满足预期条件.    /// </summary>    private static bool IsConditionMet(object current, object expected)    {        if (current == null && expected == null)        {            return true;        }        if (current == null || expected == null)        {            return false;        }        if (current.GetType().IsEnum)        {            return current.Equals(expected) ||                   current.ToString() == expected.ToString() ||                   ((int)current).ToString() == expected.ToString();        }        return current.Equals(expected);    }    #endregion}